const now = new Date();
const pad = n => String(n).padStart(2, '0');
const yesterday = new Date(now.getTime() - 86400000);
const yesterdayStr = yesterday.getFullYear() + '-' + pad(yesterday.getMonth() + 1) + '-' + pad(yesterday.getDate());
const months = ['januari','februari','mars','april','maj','juni','juli','augusti','september','oktober','november','december'];
const prevMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthLabel = months[prevMonth.getMonth()] + ' ' + prevMonth.getFullYear();
return [{ json: { yesterday: yesterdayStr, prevMonthLabel } }];

// Umami data
const rows = $('Fetch Umami Monthly').all().map(i => i.json);
const siteRows = rows.filter(r => r.record_type === 'site');
const articleRows = rows.filter(r => r.record_type === 'article');

const siteStats = {};
for (const r of siteRows) {
  if (r.domain === 'none') continue;
  siteStats[r.domain] = { this_month: parseInt(r.this_month) || 0, last_month: parseInt(r.last_month) || 0 };
}

const articlesBySite = {};
for (const r of articleRows) {
  if (!articlesBySite[r.domain]) articlesBySite[r.domain] = [];
  articlesBySite[r.domain].push({ url: r.url_path, views: parseInt(r.this_month) || 0 });
}

// LiteLLM spend
let spendLogs = [];
try {
  const raw = $('Fetch LiteLLM Spend').first().json;
  spendLogs = Array.isArray(raw) ? raw : [];
} catch (e) {}

const now = new Date();
const prevMonthDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const prevMonthPrefix = prevMonthDate.getFullYear() + '-' + String(prevMonthDate.getMonth() + 1).padStart(2, '0');
const prev2MonthDate = new Date(now.getFullYear(), now.getMonth() - 2, 1);
const prev2MonthPrefix = prev2MonthDate.getFullYear() + '-' + String(prev2MonthDate.getMonth() + 1).padStart(2, '0');

const reportMonthSpend = spendLogs.filter(d => (d.date || '').startsWith(prevMonthPrefix)).reduce((s, d) => s + (d.spend || 0), 0);
const prevMonthSpend = spendLogs.filter(d => (d.date || '').startsWith(prev2MonthPrefix)).reduce((s, d) => s + (d.spend || 0), 0);

// AI traffic
let aiText = 'Ingen AI-trafik-data tillganglig';
try {
  const aiRaw = $('Read AI Traffic').first().json;
  const body = aiRaw.Body || '';
  if (body && !aiRaw.error) {
    const ai = JSON.parse(body);
    const total = ai.total || 0;
    aiText = 'AI-referrertrafik: ' + total + ' sessioner';
    if (ai.bySource) {
      const sources = Object.entries(ai.bySource).filter(([, cnt]) => cnt > 0).slice(0, 4);
      if (sources.length) {
        aiText += ' (' + sources.map(([s, c]) => s.replace('perplexity.ai', 'perplexity').replace('chatgpt.com', 'chatgpt') + ':' + c).join(', ') + ')';
      }
    }
  }
} catch (e) {}

// GEO insights
let geoText = 'Ingen GEO-data';
try {
  const geoRaw = $('Read GEO Insights').first().json;
  const body = geoRaw.Body || '';
  if (body && !geoRaw.error) {
    const geo = JSON.parse(body);
    const insights = geo.insights || [];
    if (insights.length) {
      geoText = 'Senaste GEO-insikter: ' + insights.slice(0, 2).map(i => i.title || i.insight || '').filter(Boolean).join('; ');
    }
  }
} catch (e) {}

const dates = $('Prepare Dates').first().json;

// Build Groq prompt
let prompt = 'Manadsdata: ' + dates.prevMonthLabel + '\n\nTrafikutveckling (MoM):\n';
for (const [domain, stats] of Object.entries(siteStats)) {
  const pct = stats.last_month > 0 ? ((stats.this_month - stats.last_month) / stats.last_month * 100).toFixed(0) + '%' : 'N/A';
  prompt += domain + ': ' + stats.this_month + ' visningar (forra: ' + stats.last_month + ', forandring: ' + pct + ')\n';
}

prompt += '\nToppinnehall forra manaden:\n';
for (const [domain, arts] of Object.entries(articlesBySite)) {
  prompt += domain + ':\n';
  for (const a of arts.slice(0, 3)) {
    const slug = a.url.replace(/^\/(posts|blog|insights)\//, '').replace(/\/$/, '');
    prompt += '  - ' + slug + ' (' + a.views + ' visningar)\n';
  }
}

prompt += '\nLiteLLM-kostnad: rapportmanad $' + reportMonthSpend.toFixed(4) + ', foregaende manad $' + prevMonthSpend.toFixed(4) + '\n';
prompt += aiText + '\n';
prompt += geoText;

return [{ json: { siteStats, articlesBySite, reportMonthSpend, prevMonthSpend, dates, aiText, geoText, prompt } }];

const data = $('Assemble Data').first().json;
const groqResp = $input.first().json;

let rec = { summary: 'Manadsanalys klar.', recommendations: [] };
try {
  const raw = groqResp.choices[0].message.content;
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) rec = JSON.parse(m[0]);
} catch (e) {}

const { siteStats, articlesBySite, reportMonthSpend, prevMonthSpend, dates, aiText, geoText } = data;

const siteEmojis = {
  'emilingemarkarlsson.com': '👤',
  'thehockeyanalytics.com': '🏒',
  'thehockeybrain.com': '🧠',
  'theunnamedroads.com': '🌍',
  'theagentfabric.com': '🤖',
  'theprintroute.com': '📄'
};

const trafficLines = [];
for (const [domain, stats] of Object.entries(siteStats)) {
  const emoji = siteEmojis[domain] || '🌐';
  const diff = stats.this_month - stats.last_month;
  const pct = stats.last_month > 0 ? Math.round(diff / stats.last_month * 100) : 0;
  const arrow = diff > 0 ? '▲' : diff < 0 ? '▼' : '→';
  const sign = diff > 0 ? '+' : '';
  trafficLines.push(emoji + ' ' + domain.replace('.com', '') + ': ' + stats.this_month + ' (' + arrow + sign + pct + '%)');
}

const artLines = [];
for (const [domain, arts] of Object.entries(articlesBySite)) {
  for (const a of (arts || []).slice(0, 2)) {
    const slug = a.url.replace(/^\/(posts|blog|insights)\//, '').replace(/\/$/, '').replace(/-/g, ' ').slice(0, 45);
    artLines.push('  ' + a.views + ' – ' + slug);
  }
}

const spendDiff = reportMonthSpend - prevMonthSpend;
const spendArrow = spendDiff >= 0 ? '▲' : '▼';
const spendSign = spendDiff >= 0 ? '+' : '';

const recLines = [];
for (const r of (rec.recommendations || []).slice(0, 4)) {
  const icon = r.priority === 'hog' ? '🔴' : '🟡';
  recLines.push(icon + ' ' + (r.site ? '[' + r.site + '] ' : '') + r.action);
}

const text = '<b>Manadsrapport – ' + dates.prevMonthLabel + '</b>\n\n' +
  rec.summary + '\n\n' +
  '<b>Trafik (vs foregaende manad):</b>\n<code>' + trafficLines.join('\n') + '</code>\n\n' +
  (artLines.length ? '<b>Toppinnehall:</b>\n<code>' + artLines.join('\n') + '</code>\n\n' : '') +
  '<b>LiteLLM-kostnad:</b>\n<code>' +
  'Rapportmanad: $' + reportMonthSpend.toFixed(4) + '  ' + spendArrow + spendSign + '$' + Math.abs(spendDiff).toFixed(4) + '\n' +
  'Foregaende:   $' + prevMonthSpend.toFixed(4) + '</code>\n\n' +
  '<b>AI-trafik:</b>\n' + aiText + '\n\n' +
  '<b>Prioriteringar nasta manad:</b>\n' + recLines.join('\n');

return [{ json: { text } }];

